const embeddingResponse = $input.first().json;
const email = $('Email de Teste1').first().json.email;
const embedding = embeddingResponse.data[0].embedding;
const vectorStr = '[' + embedding.join(',') + ']';

// Monta query semantica
const semanticQuery = "SELECT chunk_id, content, metadata, 1 - (embedding <=> '" + vectorStr + "'::vector) AS score FROM documents ORDER BY embedding <=> '" + vectorStr + "'::vector LIMIT 20";

// Extrai termos para busca lexical
const stopwords = new Set([
  'para', 'com', 'por', 'que', 'uma', 'uns', 'das', 'dos', 'nos', 'nas',
  'seu', 'sua', 'orcamento', 'gostaria', 'receber', 'enviem', 'envie',
  'quero', 'favor', 'att', 'ola', 'seguintes', 'produto', 'produtos',
  'solicitacao', 'abaixo', 'segue', 'bom', 'dia', 'tarde', 'noite'
]);
const codes = email.match(/\b\d{6,7}\b/g) || [];
const words = (email.match(/\b[A-Za-z\u00C0-\u00FF0-9]{4,}\b/g) || [])
  .filter(w => !stopwords.has(w.toLowerCase()))
  .slice(0, 20);

const conditions = [];
codes.forEach(c => conditions.push("metadata->>'codigo_sap' = '" + c + "'"));
words.forEach(w => conditions.push("content ILIKE '%" + w + "%'"));
const whereClause = conditions.length > 0 ? conditions.join(' OR ') : '1=0';
const lexicalQuery = "SELECT chunk_id, content, metadata, 1.0 AS score FROM documents WHERE " + whereClause + " LIMIT 20";

return [{ json: { email, semanticQuery, lexicalQuery } }];

const items = $input.all();
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  semantic_rank: idx + 1
}));
return [{ json: { semanticResults: results } }];

const items = $input.all();
const results = items.map((item, idx) => ({
  chunk_id: item.json.chunk_id,
  content: item.json.content,
  metadata: item.json.metadata,
  lexical_rank: idx + 1
}));
return [{ json: { lexicalResults: results } }];

const email = $('Email de Teste1').first().json.email;
const semanticResults = $input.first().json.semanticResults || [];
const lexicalResults = $input.first().json.lexicalResults || [];

const K = 60; // constante padrao do RRF
const scores = {};
const docs = {};

// Score semantico
semanticResults.forEach((doc, idx) => {
  const id = doc.chunk_id;
  if (!scores[id]) scores[id] = 0;
  scores[id] += 1 / (K + idx + 1);
  docs[id] = doc;
});

// Score lexical
lexicalResults.forEach((doc, idx) => {
  const id = doc.chunk_id;
  if (!scores[id]) scores[id] = 0;
  scores[id] += 1 / (K + idx + 1);
  if (!docs[id]) docs[id] = doc;
});

// Ordena por RRF score e pega top 10
const topDocs = Object.entries(scores)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([id, score]) => ({ ...docs[id], rrf_score: score.toFixed(4) }));

const catalogText = topDocs.map(doc => {
  const m = doc.metadata;
  return 'Produto: ' + m.apresentacao +
    '\nCodigo SAP: ' + m.codigo_sap +
    '\nRRF Score: ' + doc.rrf_score +
    '\nPrecos PF  - ICMS12: R$' + m.icms_12_pf + ' | ICMS17: R$' + m.icms_17_pf + ' | ICMS18: R$' + m.icms_18_pf + ' | ICMS20: R$' + m.icms_20_pf +
    '\nPrecos PMC - ICMS12: R$' + m.icms_12_pmc + ' | ICMS17: R$' + m.icms_17_pmc + ' | ICMS18: R$' + m.icms_18_pmc + ' | ICMS20: R$' + m.icms_20_pmc +
    '\nDescricao: ' + doc.content;
}).join('\n\n---\n\n');

const formatoJSON = '{"itens":[{"produto":"","codigo":"","quantidade":0,"preco_unitario":0.0,"preco_total":0.0}],"cliente":{"tipo":"","uf":""},"total":0.0}';

const systemMessage = 'Voce e um sistema de cotacao de medicamentos farmaceuticos. '
  + 'Receberá uma mensagem de solicitacao de orcamento e produtos encontrados no catalogo ordenados por relevancia (RRF Score). '
  + 'Sua tarefa: '
  + '1) Identificar quais produtos correspondem ao solicitado. '
  + '2) Extrair quantidades (padrao 1 se nao informado). '
  + '3) Identificar tipo de cliente: PF, PJ ou Revenda. '
  + '4) Identificar UF se mencionada. '
  + '5) Calcular precos: PF e PJ usam icms_17_pf, Revenda usa icms_17_pmc, sem UF usa icms_17_pf. '
  + '6) preco_total = quantidade x preco_unitario. '
  + '7) Somar total geral. '
  + 'Responda APENAS com JSON valido, sem markdown, sem texto adicional: '
  + formatoJSON;

const userMessage = 'Mensagem do cliente:\n' + email
  + '\n\nProdutos mais relevantes (ordenados por RRF Score):\n\n' + catalogText;

const body = {
  model: 'gemma-3n-e4b-it-text',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  temperature: 0.1,
  max_tokens: 1024,
  stream: false
};

return [{ json: { body } }];

const response = $input.first().json;
const content = response.choices[0].message.content.trim();
try {
  const jsonStr = content.replace(/```json/g, '').replace(/```/g, '').trim();
  const orcamento = JSON.parse(jsonStr);
  return [{ json: orcamento }];
} catch(e) {
  return [{ json: { erro: 'Falha ao parsear JSON', raw: content } }];
}
